// Accept body from webhook (POST body is in .body or top-level)
const body = $input.first().json.body || $input.first().json;

// Split full name into first / last
const fullName = (body.name || '').trim();
const spaceIdx = fullName.indexOf(' ');
const firstName = spaceIdx > -1 ? fullName.substring(0, spaceIdx) : fullName;
const lastName  = spaceIdx > -1 ? fullName.substring(spaceIdx + 1) : '';

const emailAddr  = (body.email   || '').trim().toLowerCase();
const message    = (body.message || '').trim();

// Escape single quotes for SQL embedding
const esc = (s) => (s || '').replace(/'/g, "''");

// Pre-build Resend email payload (safe: JSON.stringify handles all escaping)
const emailHtml = [
  '<h2 style="color:#2D6A6A;font-family:sans-serif;margin-bottom:16px">New Contact Form Submission</h2>',
  '<table style="border-collapse:collapse;width:100%;max-width:600px;font-family:sans-serif;font-size:14px">',
  '<tr><td style="padding:12px;border:1px solid #ddd;background:#f5f5f5;width:100px"><strong>Name</strong></td>',
  '<td style="padding:12px;border:1px solid #ddd">' + fullName + '</td></tr>',
  '<tr><td style="padding:12px;border:1px solid #ddd;background:#f5f5f5"><strong>Email</strong></td>',
  '<td style="padding:12px;border:1px solid #ddd"><a href="mailto:' + emailAddr + '" style="color:#2D6A6A">' + emailAddr + '</a></td></tr>',
  '<tr><td style="padding:12px;border:1px solid #ddd;background:#f5f5f5"><strong>Message</strong></td>',
  '<td style="padding:12px;border:1px solid #ddd;white-space:pre-wrap">' + message + '</td></tr>',
  '</table>',
  '<p style="color:#999;font-size:12px;margin-top:16px;font-family:sans-serif">Saved to Neon DB automatically.</p>'
].join('');

const resendPayload = JSON.stringify({
  from: 'SoulSynergy Coaching <onboarding@resend.dev>',
  to: ['connect.sscoach@gmail.com'],
  subject: '\u2728 New Contact: ' + fullName,
  html: emailHtml
});

return [{
  json: {
    // SQL-safe values (single quotes escaped)
    first_name:     esc(firstName),
    last_name:      esc(lastName),
    email:          esc(emailAddr),
    message:        esc(message),
    full_name:      esc(fullName),
    // Raw values for email (not SQL)
    raw_full_name:  fullName,
    raw_email:      emailAddr,
    raw_message:    message,
    // Pre-built Resend payload string
    resend_payload: resendPayload
  }
}];
